       'sciencedirect','springerlink','google scholar','ncbi','jstor','mdpi','frontiers','pmc','x-mol','core'}
c=collections.Counter(); bad=[]
for f in glob.glob("outputs/*/bibliography.json"):
    for e in json.load(open(f)):
        v=(e.get('venue') or '').strip()
        if v:
            c[v]+=1
print("=== venue values across all bibliographies (the F+A 'source of truth') ===")
for v,n in c.most_common(28):
    tag = "  <-- NOT A VENUE (aggregator/index/host)" if v.lower() in AGG or '.' in v else ""
    print(f"{n:4d}  {v!r}{tag}")
EOF
